import{j as a,b as e,c as i,aa as l}from"./chunks/framework.Bxf40uRC.js";const q=JSON.parse('{"title":"面试问题","description":"","frontmatter":{},"headers":[],"relativePath":"RabbitMq/面试问题.md","filePath":"RabbitMq/面试问题.md","lastUpdated":null}'),t={name:"RabbitMq/面试问题.md"},o=l('<h1 id="面试问题" tabindex="-1">面试问题 <a class="header-anchor" href="#面试问题" aria-label="Permalink to &quot;面试问题&quot;">​</a></h1><h2 id="_1、你怎么保证生产者发送消息可靠" tabindex="-1">1、你怎么保证生产者发送消息可靠？ <a class="header-anchor" href="#_1、你怎么保证生产者发送消息可靠" aria-label="Permalink to &quot;1、你怎么保证生产者发送消息可靠？&quot;">​</a></h2><ol><li>首先可以配置生产者重连机制，主要解决因为网络波动导致的发送失败问题；</li><li>开启生产者确认机制，基于返回的消息，如果是nack可以进行一个重发的操作；</li><li>但是以上手段都会增加机器的负担，一般情况下不会开启这些机制，如果是对于消息可靠性要求比较高的，才会开启；</li></ol><h2 id="_2、rabbitmq如何保证消息的可靠性" tabindex="-1">2、RabbitMQ如何保证消息的可靠性 <a class="header-anchor" href="#_2、rabbitmq如何保证消息的可靠性" aria-label="Permalink to &quot;2、RabbitMQ如何保证消息的可靠性&quot;">​</a></h2><ol><li>通过配置交换机，队列，以及发送消息都持久化，这样队列中的消息都会持久化到磁盘，MQ重启消息依然会存在；</li><li>RabbitMq 引入了lazyQueue，会将所有的消息都持久化；</li><li>开启持久化和生产者确认时，只有RabbitMq只有在消息持久化之后才会给生产者返回ACK回执；</li></ol><h2 id="_3、消费者如何保证消息一定被消费" tabindex="-1">3、消费者如何保证消息一定被消费？ <a class="header-anchor" href="#_3、消费者如何保证消息一定被消费" aria-label="Permalink to &quot;3、消费者如何保证消息一定被消费？&quot;">​</a></h2><ol><li>开启消费者确认机制为auto，后续确认消息处理成功后返回ack，异常时返回nack；</li><li>开启消费者失败重试机制，并设置MessageRecover，多次重试失败后将消息投递到异常交换机，交给人工处理；</li></ol><h2 id="_4、怎么解决表单提交的幂等性" tabindex="-1">4、怎么解决表单提交的幂等性？ <a class="header-anchor" href="#_4、怎么解决表单提交的幂等性" aria-label="Permalink to &quot;4、怎么解决表单提交的幂等性？&quot;">​</a></h2><ol><li>在进入表单之前，生成一个唯一标识发送前端；redis存放一份；</li><li>在表单提交时候携带这个token，然后判断redis里面是否存在，如果存在，删除token；</li><li>重复提交redis中没有，则无法执行；</li></ol><h2 id="_5、支付服务与交易服务之间的订单状态一致性是如何保证的" tabindex="-1">5、支付服务与交易服务之间的订单状态一致性是如何保证的？ <a class="header-anchor" href="#_5、支付服务与交易服务之间的订单状态一致性是如何保证的" aria-label="Permalink to &quot;5、支付服务与交易服务之间的订单状态一致性是如何保证的？&quot;">​</a></h2><ul><li>首先，支付服务会正在用户支付成功以后利用MQ消息通知交易服务，完成订单状态同步；</li><li>其次，为了保证MQ消息的可靠性，我们采用了生产者确认机制、消费者确认、消费者失败重试等策略，确保消息投递的可靠性；</li><li>最后，我们还在交易服务设置了定时任务，定期查询订单支付状态。这样即便MQ通知失败，还可以利用定时任务作为兜底方案，确保订单支付状态的最终一致性；</li></ul>',11),r=[o];function n(_,s,d,h,c,b){return e(),i("div",null,r)}const m=a(t,[["render",n]]);export{q as __pageData,m as default};
